# lib/blog/sanitizer.ex
defmodule Blog.Sanitizer do
  @moduledoc """
  Sanitizes user-generated HTML to allow safe rich formatting
  while stripping dangerous tags like <script>, <iframe>, event handlers, etc.
  """

  # Define a custom scrubber that allows common formatting tags
  defmodule BlogScrubber do
    require HtmlSanitizeEx.Scrubber.Meta
    alias HtmlSanitizeEx.Scrubber.Meta

    # Allow basic formatting tags
    Meta.strip_comments()

    Meta.allow_tag_with_these_attributes("p", ["class"])
    Meta.allow_tag_with_these_attributes("br", [])
    Meta.allow_tag_with_these_attributes("strong", [])
    Meta.allow_tag_with_these_attributes("b", [])
    Meta.allow_tag_with_these_attributes("em", [])
    Meta.allow_tag_with_these_attributes("i", [])
    Meta.allow_tag_with_these_attributes("u", [])
    Meta.allow_tag_with_these_attributes("s", [])
    Meta.allow_tag_with_these_attributes("blockquote", ["class"])
    Meta.allow_tag_with_these_attributes("code", ["class"])
    Meta.allow_tag_with_these_attributes("pre", ["class"])
    Meta.allow_tag_with_these_attributes("ul", [])
    Meta.allow_tag_with_these_attributes("ol", [])
    Meta.allow_tag_with_these_attributes("li", [])
    Meta.allow_tag_with_these_attributes("h1", ["class"])
    Meta.allow_tag_with_these_attributes("h2", ["class"])
    Meta.allow_tag_with_these_attributes("h3", ["class"])
    Meta.allow_tag_with_these_attributes("h4", ["class"])
    Meta.allow_tag_with_these_attributes("span", ["class"])
    Meta.allow_tag_with_these_attributes("div", ["class"])
    Meta.allow_tag_with_these_attributes("table", ["class"])
    Meta.allow_tag_with_these_attributes("thead", [])
    Meta.allow_tag_with_these_attributes("tbody", [])
    Meta.allow_tag_with_these_attributes("tr", [])
    Meta.allow_tag_with_these_attributes("td", ["class", "colspan", "rowspan"])
    Meta.allow_tag_with_these_attributes("th", ["class", "colspan", "rowspan"])
    Meta.allow_tag_with_these_attributes("hr", [])

    # Allow images with restricted attributes
    Meta.allow_tag_with_uri_attributes("img", ["src"], ["https"])
    Meta.allow_tag_with_these_attributes("img", ["alt", "title", "class", "width", "height"])

    # Allow links but only with safe protocols
    Meta.allow_tag_with_uri_attributes("a", ["href"], ["https", "http", "mailto"])
    Meta.allow_tag_with_these_attributes("a", ["title", "class", "rel", "target"])

    # Strip everything else
    Meta.strip_everything_not_covered()
  end

  @doc """
  Sanitizes HTML content, allowing safe rich formatting tags
  while removing all dangerous elements (script, iframe, event handlers, etc.)
  """
  def sanitize(nil), do: ""
  def sanitize(html) when is_binary(html) do
    HtmlSanitizeEx.Scrubber.scrub(html, BlogScrubber)
  end
end

# lib/blog/posts/post.ex
defmodule Blog.Posts.Post do
  use Ecto.Schema
  import Ecto.Changeset

  schema "posts" do
    field :title, :string
    field :content, :string
    field :sanitized_content, :string
    field :author, :string

    timestamps()
  end

  def changeset(post, attrs) do
    post
    |> cast(attrs, [:title, :content, :author])
    |> validate_required([:title, :content, :author])
    |> validate_length(:title, min: 1, max: 255)
    |> validate_length(:content, min: 1, max: 50_000)
    |> sanitize_content()
  end

  defp sanitize_content(changeset) do
    case get_change(changeset, :content) do
      nil -> changeset
      content ->
        sanitized = Blog.Sanitizer.sanitize(content)
        put_change(changeset, :sanitized_content, sanitized)
    end
  end
end

# lib/blog_web/live/post_live/show.ex
defmodule BlogWeb.PostLive.Show do
  use BlogWeb, :live_view

  alias Blog.Posts

  @impl true
  def mount(%{"id" => id}, _session, socket) do
    post = Posts.get_post!(id)
    {:ok, assign(socket, :post, post)}
  end

  @impl true
  def render(assigns) do
    ~H"""
    <div class="max-w-4xl mx-auto py-8 px-4">
      <article class="blog-post">
        <header class="mb-8">
          <h1 class="text-4xl font-bold text-gray-900 mb-2"><%= @post.title %></h1>
          <div class="text-gray-500 text-sm">
            By <span class="font-medium"><%= @post.author %></span>
            · <%= Calendar.strftime(@post.inserted_at, "%B %d, %Y") %>
          </div>
        </header>

        <div class="prose prose-lg max-w-none">
          <%!--
            SECURITY: We render sanitized_content, NOT raw user content.
            The content was sanitized on save using HtmlSanitizeEx which strips
            all dangerous tags (<script>, <iframe>, event handlers like onclick, etc.)
            while preserving safe formatting tags.

            NEVER DO THIS: raw(@post.content)  — this would allow XSS attacks
          --%>
          <%= raw(@post.sanitized_content) %>
        </div>
      </article>

      <div class="mt-8 pt-8 border-t">
        <.link navigate={~p"/posts"} class="text-blue-600 hover:text-blue-800">
          ← Back to all posts
        </.link>
      </div>
    </div>
    """
  end
end

# lib/blog_web/live/post_live/index.ex
defmodule BlogWeb.PostLive.Index do
  use BlogWeb, :live_view

  alias Blog.Posts

  @impl true
  def mount(_params, _session, socket) do
    posts = Posts.list_posts()
    {:ok, assign(socket, :posts, posts)}
  end

  @impl true
  def render(assigns) do
    ~H"""
    <div class="max-w-4xl mx-auto py-8 px-4">
      <div class="flex justify-between items-center mb-8">
        <h1 class="text-3xl font-bold">Blog Posts</h1>
        <.link navigate={~p"/posts/new"} class="bg-blue-600 text-white px-4 py-2 rounded hover:bg-blue-700">
          New Post
        </.link>
      </div>

      <div class="space-y-6">
        <article :for={post <- @posts} class="border-b pb-6">
          <h2 class="text-2xl font-semibold mb-1">
            <.link navigate={~p"/posts/#{post.id}"} class="text-blue-700 hover:text-blue-900">
              <%= post.title %>
            </.link>
          </h2>
          <p class="text-gray-500 text-sm mb-3">
            By <%= post.author %> · <%= Calendar.strftime(post.inserted_at, "%B %d, %Y") %>
          </p>
          <div class="prose text-gray-700 line-clamp-3">
            <%= raw(truncate_sanitized(post.sanitized_content, 300)) %>
          </div>
        </article>
      </div>
    </div>
    """
  end

  defp truncate_sanitized(nil, _), do: ""
  defp truncate_sanitized(content, max_length) do
    if String.length(content) > max_length do
      content
      |> String.slice(0, max_length)
      |> close_open_tags()
      |> Kernel.<>("…")
    else
      content
    end
  end

  # Simple approach: re-sanitize after truncation to fix broken tags
  defp close_open_tags(html) do
    Blog.Sanitizer.sanitize(html)
  end
end

# lib/blog_web/live/post_live/form.ex
defmodule BlogWeb.PostLive.Form do
  use BlogWeb, :live_view

  alias Blog.Posts
  alias Blog.Posts.Post

  @impl true
  def mount(_params, _session, socket) do
    changeset = Posts.change_post(%Post{})

    {:ok,
     socket
     |> assign(:changeset, changeset)
     |> assign(:form, to_form(changeset))
     |> assign(:preview_html, "")}
  end

  @impl true
  def handle_event("validate", %{"post" => post_params}, socket) do
    changeset =
      %Post{}
      |> Posts.change_post(post_params)
      |> Map.put(:action, :validate)

    preview_html = Blog.Sanitizer.sanitize(post_params["content"] || "")

    {:noreply,
     socket
     |> assign(:changeset, changeset)
     |> assign(:form, to_form(changeset))
     |> assign(:preview_html, preview_html)}
  end

  @impl true
  def handle_event("save", %{"post" => post_params}, socket) do
    case Posts.create_post(post_params) do
      {:ok, post} ->
        {:noreply,
         socket
         |> put_flash(:info, "Post published successfully!")
         |> push_navigate(to: ~p"/posts/#{post.id}")}

      {:error, changeset} ->
        {:noreply,
         socket
         |> assign(:changeset, changeset)
         |> assign(:form, to_form(changeset))}
    end
  end

  @impl true
  def render(assigns) do
    ~H"""
    <div class="max-w-4xl mx-auto py-8 px-4">
      <h1 class="text-3xl font-bold mb-8">Create New Post</h1>

      <.form for={@form} phx-change="validate" phx-submit="save" class="space-y-6">
        <div>
          <label class="block text-sm font-medium text-gray-700 mb-1">Title</label>
          <input
            type="text"
            name="post[title]"
            value={@form[:title].value}
            class="w-full border rounded px-3 py-2"
            required
          />
          <.error :for={msg <- Enum.map(@form[:title].errors, &translate_error/1)}>
            <%= msg %>
          </.error>
        </div>

        <div>
          <label class="block text-sm font-medium text-gray-700 mb-1">Author</label>
          <input
            type="text"
            name="post[author]"
            value={@form[:author].value}
            class="w-full border rounded px-3 py-2"
            required
          />
        </div>

        <div>
          <label class="block text-sm font-medium text-gray-700 mb-1">
            Content (HTML formatting allowed)
          </label>
          <div class="text-xs text-gray-500 mb-2">
            Allowed tags: p, strong, em, a, img, h1-h4, ul, ol, li, blockquote, code, pre, table, br, hr.
            Dangerous tags (script, iframe, etc.) will be automatically removed.
          </div>
          <textarea
            name="post[content]"
            rows="15"
            class="w-full border rounded px-3 py-2 font-mono text-sm"
            required
          ><%= @form[:content].value %></textarea>
        </div>

        <div>
          <h3 class="text-lg font-semibold mb-2 text-gray-700">Preview</h3>
          <div class="border rounded p-6 bg-gray-50 prose prose-lg max-w-none min-h-[100px]">
            <%= if @preview_html != "" do %>
              <%= raw(@preview_html) %>
            <% else %>
              <p class="text-gray-400 italic">Start typing to see a preview...</p>
            <% end %>
          </div>
        </div>

        <div class="flex gap-4">
          <button type="submit" class="bg-blue-600 text-white px-6 py-2 rounded hover:bg-blue-700">
            Publish Post
          </button>
          <.link navigate={~p"/posts"} class="px-6 py-2 text-gray-600 hover:text-gray-800">
            Cancel
          </.link>
        </div>
      </.form>
    </div>
    """
  end

  defp translate_error({msg, opts}) do
    Enum.reduce(opts, msg, fn {key, value}, acc ->
      String.replace(acc, "%{#{key}}", fn _ -> to_string(value) end)
    end)
  end
end

# lib/blog/posts.ex
defmodule Blog.Posts do
  import Ecto.Query
  alias Blog.Repo
  alias Blog.Posts.Post

  def list_posts do
    Post
    |> order_by(desc: :inserted_at)
    |> Repo.all()
  end

  def get_post!(id), do: Repo.get!(Post, id)

  def create_post(attrs \\ %{}) do
    %Post{}
    |> Post.changeset(attrs)
    |> Repo.insert()
  end

  def change_post(%Post{} = post, attrs \\ %{}) do
    Post.changeset(post, attrs)
  end
end

